class Solution:
    def containsDuplicate(self, nums):
        s = sorted(nums)
        for i in range(1, len(s)):
            if s[i] == s[i - 1]:
                return True
        return False

solutions.python:
class Solution:
    def containsDuplicate(self, nums):
        seen = set()
        for v in nums:
            if v in seen:
                return True
            seen.add(v)
        return False

